    override fun onCreate() {
        super.onCreate()
        Log.i(TAG, "[RustExternalLayerRadicleService] Service creating in pid ${Process.myPid()}")
        
        // Create notification channel for foreground service
        if (Build.VERSION.SDK_INT >= Build.VERSION_CODES.O) {
            val channel = NotificationChannel(
                CHANNEL_ID,
                "RustExternalLayerRadicleService",
                NotificationManager.IMPORTANCE_LOW
            ).apply {
                description = "Background service for RustExternalLayer"
                setShowBadge(false)
            }
            
            val notificationManager = getSystemService(Context.NOTIFICATION_SERVICE) as NotificationManager
            notificationManager.createNotificationChannel(channel)
        }
        
        // Start as foreground service
        startForeground(NOTIFICATION_ID, createNotification())
        Log.i(TAG, "[RustExternalLayerRadicleService] Started as foreground service")
    }
    
    override fun onStartCommand(intent: Intent?, flags: Int, startId: Int): Int {
        Log.i(TAG, "[RustExternalLayerRadicleService] Service starting (startId=$startId)")
        
        val homeDir = getDir(".RustExternalLayer", Context.MODE_PRIVATE).absolutePath
        val alias = intent?.getStringExtra("alias") ?: "android"
        
        // Start the native service in a background thread
        Thread {
            try {
                nativeHandle = nativeStartService(homeDir, alias)
                if (nativeHandle < 0) {
                    Log.e(TAG, "[RustExternalLayerRadicleService] Native service failed to start")
                    stopSelf(startId)
                    return@Thread
                }
                
                Log.i(TAG, "[RustExternalLayerRadicleService] Native service started with handle=$nativeHandle")
                
                // Service keeps running until explicitly stopped
                // The Rust core runs its own event loop
                Thread.currentThread().join()
                
                Log.w(TAG, "[RustExternalLayerRadicleService] Native service thread exited unexpectedly")
            } catch (e: Exception) {
                Log.e(TAG, "[RustExternalLayerRadicleService] Native service crashed: ${e.message}", e)
            } finally {
                if (nativeHandle != 0L) {
                    nativeStopService(nativeHandle)
                }
                nativeHandle = 0
                stopSelf(startId)
            }
        }.apply {
            name = "RustExternalLayerRadicleService-Thread-$startId"
            start()
        }
        
        return START_STICKY
    }
    
    /**
     * Called when a client binds to this service.
     * 
     * Returns the AIDL binder stub that implements IFoundframeRadicle interface.
     * This enables cross-process IPC for apps with the same signing key.
     * 
     * @param intent The Intent that was used to bind to this service
     * @return IBinder The AIDL interface implementation
     */
    override fun onBind(intent: Intent): IBinder {
        Log.i(TAG, "[RustExternalLayerRadicleService] onBind() - returning AIDL binder")
        return aidlBinder
    }
    
    override fun onDestroy() {
        super.onDestroy()
        Log.i(TAG, "[RustExternalLayerRadicleService] Service destroying")
        if (nativeHandle != 0L) {
            nativeStopService(nativeHandle)
            nativeHandle = 0
        }
    }
    
    /**
     * Check if the native service is ready for AIDL calls.
     * Clients can use this to verify the service is initialized before calling methods.
     */
    fun isReady(): Boolean = nativeHandle != 0L
    
    private fun createNotification(): Notification {
        val builder = if (Build.VERSION.SDK_INT >= Build.VERSION_CODES.O) {
            Notification.Builder(this, CHANNEL_ID)
        } else {
            @Suppress("DEPRECATION")
            Notification.Builder(this)
        }
        
        return builder
            .setContentTitle("RustExternalLayer Service")
            .setContentText("Running in background")
            .setSmallIcon(android.R.drawable.ic_menu_share)
            .setOngoing(true)
            .build()
    }
